let items = $input.all(); let results = [];
const EXCLUDE_PREFIXES = [/^Detalhe_/i, /^News_/i];
const seenMessages = new Set();
const BASE_FOLDER_ID = '1e6LXLUDgJHVplJlh9MTSYs-GL62Ahv30';

// Build folder ID mapping from Create Month Folder output
// Items from Create Month Folder have monthYear and id (the created folder's ID)
// Items from Merge have email data with binary attachments
const folderIds = {};
const emailItems = [];

for (const item of items) {
  if (item.json.monthYear && item.json.id && !item.json.internalDate) {
    // This is a folder creation response
    folderIds[item.json.monthYear] = item.json.id;
  } else if (item.json.internalDate || item.json.id) {
    // This is email data
    emailItems.push(item);
  }
}

// Process email items
seenMessages.clear();
for (const item of emailItems) {
  const rawDate = item.json.internalDate || item.json.date || item.json.headers?.date || null;
  if (!rawDate && !item.json.id) continue;

  let date;
  if (rawDate && !isNaN(rawDate)) date = new Date(Number(rawDate));
  else if (rawDate) date = new Date(rawDate);
  else date = new Date();
  if (isNaN(date.getTime())) date = new Date();

  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();
  const monthYear = month + '-' + year;

  const msgId = item.json.id || item.json.messageId || JSON.stringify(item.json);
  if (seenMessages.has(msgId)) continue;
  seenMessages.add(msgId);

  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      const bin = item.binary[key];
      const fileName = (bin.fileName || '').trim();
      const fileNameLc = fileName.toLowerCase();
      const isPdf = (bin.mimeType && bin.mimeType.toLowerCase().includes('pdf')) || fileNameLc.endsWith('.pdf');
      if (!isPdf) continue;
      if (EXCLUDE_PREFIXES.some((re) => re.test(fileName))) continue;

      const folderId = folderIds[monthYear] || BASE_FOLDER_ID;
      results.push({ json: { monthYear, fileName, folderId }, binary: { data: bin } });
    }
  }
}
return results;

// Aggregate results for notification
const items = $input.all();
const folderCounts = {};
let totalFiles = 0;

for (const item of items) {
  const folder = item.json.folderId || 'unknown';
  if (!folderCounts[folder]) folderCounts[folder] = 0;
  folderCounts[folder]++;
  totalFiles++;
}

const folders = Object.keys(folderCounts).join(', ');
const msg = `Monthly Invoice extracts completed. Total files: ${totalFiles}. Folders: ${folders}`;

return [{ json: { 
  message: msg, 
  totalFiles, 
  folders: Object.keys(folderCounts).join(', '),
  webhook_secret: 'n8n-webhook-secret-2024',
  webhook_url: 'http://192.168.50.11:8644/webhooks/n8n-complete'
} }];

// Extract unique month-years for folder creation
const emails = $input.all();
const monthYears = new Set();

for (const email of emails) {
  const rawDate = email.json.internalDate || email.json.date || email.json.headers?.date || null;
  let date;
  if (rawDate && !isNaN(rawDate)) date = new Date(Number(rawDate));
  else if (rawDate) date = new Date(rawDate);
  else date = new Date();
  if (isNaN(date.getTime())) date = new Date();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();
  monthYears.add(month + '-' + year);
}

// Output items for folder creation
return Array.from(monthYears).map(my => ({ json: { monthYear: my } }));
